// damacy_bench — exercises the public damacy API end-to-end.
//
// Step 4: drives a real on-disk zarr through the synchronous pipeline.
// Pass --root and --uri to point at a store generated by
// `bench/gen_dataset.py`. Without --root, the bench just creates and
// destroys a damacy instance to verify the API shape compiles + binds
// to the current CUDA context.
//
//   ./damacy_bench [--root PATH] [--uri NAME]
//                  [--rank R] [--shape z,y,x]
//                  [--batches N] [--batch-size N] [--lookahead N]
//                  [--io-threads N] [--host-buffer-mb N]
//                  [--device-buffer-mb N] [--peek]
#include "damacy.h"

#include <cuda_runtime.h>
#include <stdint.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>

static double
now_seconds(void)
{
  struct timespec ts;
  clock_gettime(CLOCK_MONOTONIC, &ts);
  return (double)ts.tv_sec + (double)ts.tv_nsec / 1e9;
}

struct bench_args
{
  const char* root;
  const char* uri;
  uint32_t n_batches;
  uint32_t batch_size;
  uint32_t lookahead_batches;
  uint32_t n_io_threads;
  uint64_t host_buffer_bytes;
  uint64_t device_buffer_bytes;
  uint8_t rank;
  int64_t shape[8];
  int peek;
};

static void
usage(const char* argv0)
{
  fprintf(
    stderr,
    "usage: %s [opts]\n"
    "  --root PATH           filesystem root for samples (no default)\n"
    "  --uri NAME            zarr name relative to --root (default \"0\")\n"
    "  --rank R              sample rank (default 3)\n"
    "  --shape z,y,x         per-axis sample extent (default 32,128,128)\n"
    "  --batches N           total batches to drive (default 50)\n"
    "  --batch-size N        samples per batch (default 8)\n"
    "  --lookahead N         lookahead batches (default 4)\n"
    "  --io-threads N        io_queue worker threads (default 8)\n"
    "  --host-buffer-mb N    pinned staging total MB (default 256)\n"
    "  --device-buffer-mb N  device decompress total MB (default 512)\n"
    "  --peek                copy + print first 16 elements of the "
    "first popped batch\n",
    argv0);
}

static int
parse_shape_csv(const char* s, int64_t* out, uint8_t cap, uint8_t* out_rank)
{
  uint8_t n = 0;
  while (*s && n < cap) {
    char* end = NULL;
    long long v = strtoll(s, &end, 10);
    if (end == s)
      return 1;
    out[n++] = (int64_t)v;
    s = end;
    if (*s == ',')
      ++s;
    else if (*s != '\0')
      return 1;
  }
  if (n == 0)
    return 1;
  *out_rank = n;
  return 0;
}

static int
parse_args(int argc, char** argv, struct bench_args* out)
{
  *out = (struct bench_args){
    .root = NULL,
    .uri = "0",
    .n_batches = 50,
    .batch_size = 8,
    .lookahead_batches = 4,
    .n_io_threads = 8,
    .host_buffer_bytes = 256ull << 20,
    .device_buffer_bytes = 512ull << 20,
    .rank = 3,
    .shape = { 32, 128, 128, 0, 0, 0, 0, 0 },
  };
  for (int i = 1; i < argc; ++i) {
    const char* a = argv[i];
#define NEXT()                                                                 \
  ((++i < argc) ? argv[i] : (usage(argv[0]), exit(1), (const char*)NULL))
    if (strcmp(a, "--root") == 0)
      out->root = NEXT();
    else if (strcmp(a, "--uri") == 0)
      out->uri = NEXT();
    else if (strcmp(a, "--rank") == 0)
      out->rank = (uint8_t)atoi(NEXT());
    else if (strcmp(a, "--shape") == 0) {
      if (parse_shape_csv(NEXT(), out->shape, 8, &out->rank)) {
        usage(argv[0]);
        return -1;
      }
    } else if (strcmp(a, "--batches") == 0)
      out->n_batches = (uint32_t)atoi(NEXT());
    else if (strcmp(a, "--batch-size") == 0)
      out->batch_size = (uint32_t)atoi(NEXT());
    else if (strcmp(a, "--lookahead") == 0)
      out->lookahead_batches = (uint32_t)atoi(NEXT());
    else if (strcmp(a, "--io-threads") == 0)
      out->n_io_threads = (uint32_t)atoi(NEXT());
    else if (strcmp(a, "--host-buffer-mb") == 0)
      out->host_buffer_bytes = (uint64_t)atoll(NEXT()) << 20;
    else if (strcmp(a, "--device-buffer-mb") == 0)
      out->device_buffer_bytes = (uint64_t)atoll(NEXT()) << 20;
    else if (strcmp(a, "--peek") == 0)
      out->peek = 1;
    else {
      usage(argv[0]);
      return -1;
    }
#undef NEXT
  }
  return 0;
}

// Generate a sample whose AABB is `args->shape`-sized, anchored at the
// origin. v1 sliding/random sampling is out of scope; same window over
// and over still exercises the pipeline (and the LRU caches will hit).
static struct damacy_sample
make_sample(const struct bench_args* args)
{
  struct damacy_sample s = { .uri = args->uri };
  s.aabb.rank = args->rank;
  for (uint8_t d = 0; d < args->rank; ++d)
    s.aabb.dims[d] =
      (struct damacy_interval){ .beg = 0, .end = args->shape[d] };
  return s;
}

int
main(int argc, char** argv)
{
  struct bench_args args;
  if (parse_args(argc, argv, &args) != 0)
    return 1;

  struct damacy_config cfg = {
    .store_root = args.root ? args.root : ".",
    .batch_size = args.batch_size,
    .lookahead_batches = args.lookahead_batches,
    .n_io_threads = args.n_io_threads,
    .host_buffer_bytes = args.host_buffer_bytes,
    .device_buffer_bytes = args.device_buffer_bytes,
    .n_zarrs_meta_cache = 4096,
    .n_shards_meta_cache = 16384,
    .dtype = DAMACY_U16,
  };

  struct damacy* d = NULL;
  enum damacy_status s = damacy_create(&cfg, &d);
  if (s != DAMACY_OK) {
    fprintf(stderr, "damacy_create: %s\n", damacy_status_str(s));
    return 1;
  }
  if (!args.root) {
    fprintf(stderr, "no --root; create/destroy only.\n");
    damacy_destroy(d);
    return 0;
  }

  const uint32_t n_samples = args.n_batches * args.batch_size;
  struct damacy_sample* samples =
    (struct damacy_sample*)calloc(n_samples, sizeof(*samples));
  if (!samples) {
    fprintf(stderr, "alloc samples failed\n");
    damacy_destroy(d);
    return 1;
  }
  for (uint32_t i = 0; i < n_samples; ++i)
    samples[i] = make_sample(&args);

  double t0 = now_seconds();

  uint64_t pushed = 0;
  uint64_t popped = 0;
  int peeked = 0;
  struct damacy_sample_slice pending = { .beg = samples,
                                         .end = samples + n_samples };
  while (popped < args.n_batches) {
    if (pending.beg != pending.end) {
      struct damacy_push_result pr = damacy_push(d, pending);
      pushed += (uint64_t)(pr.unconsumed.beg - pending.beg);
      pending = pr.unconsumed;
      if (pr.status != DAMACY_OK && pr.status != DAMACY_AGAIN) {
        fprintf(stderr, "damacy_push: %s\n", damacy_status_str(pr.status));
        break;
      }
    }
    struct damacy_batch* b = NULL;
    enum damacy_status ps = damacy_pop(d, &b);
    if (ps == DAMACY_OK) {
      ++popped;
      if (args.peek && !peeked) {
        struct damacy_batch_info info;
        damacy_batch_info(b, &info);
        printf("first batch: rank=%u dtype=%d batch_id=%llu shape=[",
               info.rank,
               (int)info.dtype,
               (unsigned long long)info.batch_id);
        for (uint8_t dd = 0; dd < info.rank; ++dd)
          printf("%lld%s",
                 (long long)info.shape[dd],
                 dd + 1 == info.rank ? "]\n" : ",");
        uint16_t buf[16] = { 0 };
        cudaError_t ce =
          cudaMemcpy(buf, info.device_ptr, sizeof(buf), cudaMemcpyDeviceToHost);
        if (ce == cudaSuccess) {
          printf("first 16 u16 values:");
          for (int j = 0; j < 16; ++j)
            printf(" %u", (unsigned)buf[j]);
          printf("\n");
        }
        peeked = 1;
      }
      damacy_release(d, b);
    } else if (ps == DAMACY_AGAIN) {
      // Queue not yet full or still working; keep pushing if we have more.
      if (pending.beg == pending.end)
        break;
    } else {
      fprintf(stderr, "damacy_pop: %s\n", damacy_status_str(ps));
      break;
    }
  }

  if (pending.beg != pending.end || popped < args.n_batches) {
    enum damacy_status fs = damacy_flush(d);
    if (fs != DAMACY_OK)
      fprintf(stderr, "damacy_flush: %s\n", damacy_status_str(fs));
    struct damacy_batch* b = NULL;
    while (damacy_pop(d, &b) == DAMACY_OK) {
      ++popped;
      damacy_release(d, b);
    }
  }

  double t1 = now_seconds();

  struct damacy_stats stats;
  damacy_stats_get(d, &stats);

  printf("samples pushed:         %llu\n", (unsigned long long)pushed);
  printf("batches popped:         %llu\n", (unsigned long long)popped);
  printf("wall:                   %.3f s\n", t1 - t0);
  printf("batches_emitted:        %llu\n",
         (unsigned long long)stats.batches_emitted);
  printf("waves_emitted:          %llu\n",
         (unsigned long long)stats.waves_emitted);
  printf("zarr_meta hits/misses:  %llu/%llu\n",
         (unsigned long long)stats.zarr_meta_hits,
         (unsigned long long)stats.zarr_meta_misses);
  printf("shard_idx hits/misses:  %llu/%llu\n",
         (unsigned long long)stats.shard_idx_hits,
         (unsigned long long)stats.shard_idx_misses);

  free(samples);
  damacy_destroy(d);
  return 0;
}
